func FetchURLPreview(ctx echo.Context) error {
	// Parse request body
	var reqBody RequestBody
	if err := ctx.Bind(&reqBody); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if reqBody.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create a context with 3-second timeout
	ctxWithTimeout, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create HTTP request
	req, err := http.NewRequestWithContext(ctxWithTimeout, "GET", reqBody.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Execute the request
	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		// Check if the error was due to timeout
		if ctxWithTimeout.Err() == context.DeadlineExceeded {
			return ctx.JSON(http.StatusGatewayTimeout, map[string]string{"error": "Request timed out"})
		}
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Check response status
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Received non-200 status code: %d", resp.StatusCode)})
	}

	// Read the response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Parse HTML to extract title and meta description
	title, description := parseHTML(body)

	// Return the response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML parses the HTML content and extracts the title and meta description
func parseHTML(htmlContent []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil {
				title = n.FirstChild.Data
			}
		}
		if n.Type == html.ElementNode && n.Data == "meta" {
			isDesc := false
			content := ""
			for _, attr := range n.Attr {
				if attr.Key == "name" && attr.Val == "description" {
					isDesc = true
				}
				if attr.Key == "content" {
					content = attr.Val
				}
			}
			if isDesc && content != "" {
				description = content
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)
	return title, description
}

