// FetchURLPreview handles the request to fetch and parse URL metadata
func FetchURLPreview(ctx echo.Context) error {
	// Parse request body
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request context with timeout
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create HTTP request
	httpReq, err := http.NewRequestWithContext(reqCtx, "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Set a User-Agent header to avoid being blocked by some servers
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute the request
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	// Check if the response status is OK
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL: status code " + resp.Status})
	}

	// Read the response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Parse HTML to extract title and meta description
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	preview := parseHTML(doc)

	return ctx.JSON(http.StatusOK, preview)
}

// parseHTML recursively traverses the HTML nodes to find title and meta description
func parseHTML(n *html.Node) URLPreviewResponse {
	var response URLPreviewResponse
	var titleFound, descFound bool

	// Helper function to traverse nodes
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// If we have found both, we can stop early
		if titleFound && descFound {
