	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the request to fetch URL preview data
func FetchURLPreview(ctx echo.Context) error {
	// Parse request body
	var req RequestBody
	if err := ctx.Bind(&req); err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, "Invalid request body")
	}

	if req.URL == "" {
		return echo.NewHTTPError(http.StatusBadRequest, "URL is required")
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request context with timeout
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create HTTP request
	httpReq, err := http.NewRequestWithContext(reqCtx, "GET", req.URL, nil)
	if err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, "Invalid URL format")
	}

	// Set a user agent to avoid being blocked by some servers
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute the request
	resp, err := client.Do(httpReq)
	if err != nil {
		return echo.NewHTTPError(http.StatusBadGateway, "Failed to fetch URL: "+err.Error())
	}
	defer resp.Body.Close()

	// Check status code
	if resp.StatusCode != http.StatusOK {
		return echo.NewHTTPError(http.StatusBadGateway, "URL returned non-200 status: "+resp.Status)
	}

	// Read the response body
	bodyBytes, err := io.ReadAll(resp.Body)
	if err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, "Failed to read response body")
	}

	// Parse HTML to extract title and meta description
	title, description := parseHTML(bodyBytes)

	// Prepare response
	response := PreviewResponse{
		Title:       title,
		Description: description,
	}

	return ctx.JSON(http.StatusOK, response)
}

// parseHTML parses the HTML content and extracts title and meta description
func parseHTML(htmlContent []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title, description string
	var traverse func(*html.Node)

	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			case "meta":
				var prop, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" || attr.Key == "property" {
						prop = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				// Check for common meta description tags
				if prop == "description" || prop == "og:description" || prop == "twitter:description" {
					if description == "" { // Prefer the first one found
						description = content
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

