type ResponseBody struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the request to fetch and parse URL preview data
func FetchURLPreview(ctx echo.Context) error {
	// 1. Parse Request Body
	reqBody := new(RequestBody)
	if err := ctx.Bind(reqBody); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if reqBody.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// 2. Fetch Content with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	req, err := http.NewRequestWithContext(context.Background(), "GET", reqBody.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	// Set a generic User-Agent to avoid being blocked by some servers
	req.Header.Set("User-Agent", "GoLang-URL-Preview-Bot/1.0")

	resp, err := client.Do(req)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL (timeout or network error)"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Target URL returned non-200 status code"})
	}

	// 3. Parse HTML to extract Title and Meta Description
	title, description := parseHTML(resp.Body)

	// 4. Return Response
	return ctx.JSON(http.StatusOK, ResponseBody{
		Title:       title,
		Description: description,
	})
}

// parseHTML reads the HTML body and extracts the <title> and <meta name="description">
func parseHTML(body io.Reader) (string, string) {
	doc, err := html.Parse(body)
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)

	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Check for Title
			if n.Data == "title" {
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			}

			// Check for Meta Description
			if n.Data == "meta" {
