					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDesc && content != "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return title, description
}

