// FetchURLPreview handles the request to fetch and parse URL metadata
func FetchURLPreview(ctx echo.Context) error {
    // Parse request body
    var reqBody RequestBody
    if err := ctx.Bind(&reqBody); err != nil {
        return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
    }

    if reqBody.URL == "" {
        return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
    }

    // Create HTTP client with 3-second timeout
    client := &http.Client{
        Timeout: 3 * time.Second,
    }

    // Create request context with timeout
    reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
    defer cancel()

    // Create HTTP GET request
    req, err := http.NewRequestWithContext(reqCtx, "GET", reqBody.URL, nil)
    if err != nil {
        return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
    }

    // Set a generic User-Agent to avoid being blocked by some servers
    req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

    // Execute the request
    resp, err := client.Do(req)
    if err != nil {
        return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
    }
    defer resp.Body.Close()

    // Check if the response status is OK
    if resp.StatusCode != http.StatusOK {
        return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Received non-200 response from URL"})
    }

    // Read the response body
    bodyBytes, err := io.ReadAll(resp.Body)
    if err != nil {
        return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
    }

    // Parse HTML to extract title and description
    title, description := parseHTML(bodyBytes)

    // Return the result
    return ctx.JSON(http.StatusOK, ResponseData{
        Title:       title,
        Description: description,
    })
}

// parseHTML parses the HTML content and extracts the title and meta description
func parseHTML(htmlContent []byte) (string, string) {
    doc, err := html.Parse(strings.NewReader(string(htmlContent)))
    if err != nil {
        return "", ""
    }

    var title, description string
    var f func(*html.Node)
    f = func(n *html.Node) {
        if n.Type == html.ElementNode {
            switch n.Data {
            case "title":
                // Extract text content of the title tag
                if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
                    title = n.FirstChild.Data
                }
            case "meta":
                // Check for meta description
                isDescription := false
                content := ""
                for _, attr := range n.Attr {
                    if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
                        isDescription = true
                    }
                    if attr.Key == "property" && strings.ToLower(attr.Val) == "og:description" {
                        isDescription = true
                    }
                    if attr.Key == "content" {
                        content = attr.Val
                    }
                }
                if isDescription && content != "" {
                    description = content
                }
            }
        }
        // Traverse the tree
        for c := n.FirstChild; c != nil; c = c.NextSibling {
            f(c)
        }
    }
    f(doc)

    return title, description
}

func main() {
    e := echo.New()

    // Middleware
    e.Use(middleware.Logger())
    e.Use(middleware.Recover())

    // Register the handler
    e.POST("/preview", FetchURLPreview)

    // Start server
    e.Logger.Fatal(e.Start(":8080"))
}

